import type { Meta, StoryObj } from '@storybook/react-vite';
import { Avatar } from './Avatar';
import { Space } from '../Space';
import { UserGlyph } from '../../stories/icons';

const meta = {
  title: 'Components/Avatar',
  component: Avatar,
  tags: ['autodocs'],
  argTypes: {
    size: { control: 'select', options: ['large', 'default', 'small'] },
    shape: { control: 'inline-radio', options: ['circle', 'square'] },
    fit: { control: 'select', options: ['fill', 'contain', 'cover', 'none', 'scale-down'] },
    src: { control: 'text' },
    icon: { control: false },
  },
  args: {
    children: 'EC',
  },
} satisfies Meta<typeof Avatar>;

export default meta;
type Story = StoryObj<typeof meta>;

export const Playground: Story = {};

export const Image: Story = {
  render: () => (
    <Space align="center">
      <Avatar src="https://i.pravatar.cc/120?img=12" />
      <Avatar src="https://i.pravatar.cc/120?img=32" />
      <Avatar src="https://i.pravatar.cc/120?img=5" />
    </Space>
  ),
};

export const Fallbacks: Story = {
  name: 'Text and icon fallbacks',
  render: () => (
    <Space align="center">
      <Avatar>EC</Avatar>
      <Avatar style={{ background: 'var(--ec-color-primary)' }}>AL</Avatar>
      <Avatar icon={UserGlyph} />
    </Space>
  ),
};

export const Shapes: Story = {
  render: () => (
    <Space align="center">
      <Avatar shape="circle">C</Avatar>
      <Avatar shape="square">S</Avatar>
      <Avatar shape="square" src="https://i.pravatar.cc/120?img=20" />
    </Space>
  ),
};

export const Sizes: Story = {
  render: () => (
    <Space align="center">
      <Avatar size="large">L</Avatar>
      <Avatar>M</Avatar>
      <Avatar size="small">S</Avatar>
      <Avatar size={64}>64</Avatar>
    </Space>
  ),
};

import {
  type CSSProperties,
  forwardRef,
  type HTMLAttributes,
  type ReactNode,
  type SyntheticEvent,
  useEffect,
  useState,
} from 'react';
import { cls, useNamespace } from '../../utils';

export type AvatarSize = 'large' | 'default' | 'small' | number;

export type AvatarShape = 'circle' | 'square';

export type AvatarFit = 'fill' | 'contain' | 'cover' | 'none' | 'scale-down';

export interface AvatarProps extends HTMLAttributes<HTMLSpanElement> {
  /** Size token or explicit pixel size. */
  size?: AvatarSize;
  /** Shape of the avatar. */
  shape?: AvatarShape;
  /** Image source. */
  src?: string;
  /** Image `srcset`. */
  srcSet?: string;
  /** Image alternative text. */
  alt?: string;
  /** How the image fits its box. */
  fit?: AvatarFit;
  /** Fallback icon when no image is available. */
  icon?: ReactNode;
  /** Fired when the image fails to load. Return `false` to keep showing it. */
  onError?: (e: SyntheticEvent<HTMLImageElement>) => boolean | void;
  children?: ReactNode;
}

export const Avatar = forwardRef<HTMLSpanElement, AvatarProps>(function Avatar(props, ref) {
  const {
    size = 'default',
    shape = 'circle',
    src,
    srcSet,
    alt,
    fit = 'cover',
    icon,
    onError,
    className,
    style,
    children,
    ...rest
  } = props;

  const ns = useNamespace('avatar');
  const [hasLoadError, setHasLoadError] = useState(false);

  // Reset the error state whenever the source changes.
  useEffect(() => {
    setHasLoadError(false);
  }, [src, srcSet]);

  const handleError = (e: SyntheticEvent<HTMLImageElement>) => {
    const keep = onError?.(e);
    if (keep !== false) {
      setHasLoadError(true);
    }
  };

  const isImageSize = typeof size === 'number';

  const classes = cls(
    ns.b(),
    ns.m(shape),
    !isImageSize && size !== 'default' && ns.m(size),
    Boolean(icon) && ns.m('icon'),
    className,
  );

  const sizeStyle: CSSProperties = isImageSize
    ? { width: `${size}px`, height: `${size}px`, fontSize: `${size / 2}px` }
    : {};

  const showImage = Boolean(src || srcSet) && !hasLoadError;

  return (
    <span ref={ref} className={classes} style={{ ...sizeStyle, ...style }} {...rest}>
      {showImage ? (
        <img
          className={ns.e('image')}
          src={src}
          srcSet={srcSet}
          alt={alt}
          style={{ objectFit: fit }}
          onError={handleError}
        />
      ) : icon ? (
        <span className={ns.e('icon')}>{icon}</span>
      ) : (
        children
      )}
    </span>
  );
});

.ec-avatar {
  --ec-avatar-size: 40px;
  --ec-avatar-font-size: var(--ec-font-size-base);
  --ec-avatar-icon-size: 18px;
  --ec-avatar-bg-color: var(--ec-text-color-disabled);
  --ec-avatar-text-color: var(--ec-color-white);
  --ec-avatar-border-radius: var(--ec-border-radius-circle);

  display: inline-flex;
  align-items: center;
  justify-content: center;
  box-sizing: border-box;
  width: var(--ec-avatar-size);
  height: var(--ec-avatar-size);
  overflow: hidden;
  font-family: inherit;
  font-size: var(--ec-avatar-font-size);
  line-height: 1;
  white-space: nowrap;
  color: var(--ec-avatar-text-color);
  background-color: var(--ec-avatar-bg-color);
  border-radius: var(--ec-avatar-border-radius);
  user-select: none;
}

.ec-avatar__image {
  display: block;
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.ec-avatar__icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
}

/* ---- Shapes ---- */
.ec-avatar--circle {
  --ec-avatar-border-radius: var(--ec-border-radius-circle);
}

.ec-avatar--square {
  --ec-avatar-border-radius: var(--ec-border-radius-base);
}

/* ---- Icon ---- */
.ec-avatar--icon {
  font-size: var(--ec-avatar-icon-size);
}

/* ---- Sizes ---- */
.ec-avatar--large {
  --ec-avatar-size: 56px;
  --ec-avatar-font-size: var(--ec-font-size-extra-large);
}

.ec-avatar--small {
  --ec-avatar-size: 24px;
  --ec-avatar-font-size: var(--ec-font-size-small);
}
